for i,d in enumerate(data["demos"]):
    inp=d["input"]; out=d["output"]
    key=inp[0][0]
    # compare row by row, find shift
    print(f"--- demo {i} key={key} ---")
    # Try global vertical shift of rows 2..11 region (everything except row0,row1)
    for shift in range(0,8):
        # build shifted: row0 same, rows 2.. shifted down by `shift`
        works=True
        # naive: out row r == in row r-shift for r in 2..11
        for r in range(len(out)):
            for c in range(len(out[0])):
                exp = 0
                if r==0: exp=inp[0][c]
                elif r>=2+shift and (r-shift)>=2 and (r-shift)<len(inp):
                    exp=inp[r-shift][c]
                else:
                    exp=0
                if out[r][c]!=exp:
                    works=False;break
            if not works:break
        if works:
            print("  GLOBAL shift down by",shift,"WORKS")
